const cleanArg = (value) => {
  const text = String(value == null ? '' : value).trim();
  return /^\{[a-zA-Z0-9_]+\}$/.test(text) ? '' : text;
};
const attachmentPath = cleanArg(arg0);
if (!attachmentPath) throw new Error('attachment_file_path is required');
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
const normalize = (value) => (value || '').replace(/\u00a0/g, ' ').replace(/\s+/g, ' ').trim();
const isVisible = (node) => {
  if (!node || !(node instanceof Element)) return false;
  const style = window.getComputedStyle(node);
  if (style.visibility === 'hidden' || style.display === 'none') return false;
  const rect = node.getBoundingClientRect();
  return rect.width > 0 && rect.height > 0;
};
const labelOf = (node) => normalize([
  node.getAttribute('aria-label') || '',
  node.getAttribute('title') || '',
  node.getAttribute('data-testid') || '',
  node.textContent || ''
].join(' '));
const temporaryChatActive = () => new URLSearchParams(window.location.search).get('temporary-chat') === 'true';
const findComposer = () => Array.from(document.querySelectorAll("#prompt-textarea, textarea[placeholder*='Describe' i], textarea[placeholder*='Message' i], textarea[placeholder*='Send a message' i], form textarea, div[role='textbox'][contenteditable='true'], [contenteditable='true'][data-testid*='composer']")).find(isVisible) || null;
const findTemporaryToggle = () => Array.from(document.querySelectorAll("button, [role='button']")).filter(isVisible).find((node) => /temporary chat/.test(labelOf(node).toLowerCase())) || null;
const ensureImagesSurface = async () => {
  const actions = [];
  const temporaryToggle = findTemporaryToggle();
  if (temporaryChatActive() && temporaryToggle) {
    temporaryToggle.click();
    await sleep(700);
    actions.push('toggled_temporary_chat_off');
  }
  let composer = findComposer();
  if (composer) return { ready: true, actions };
  const deadline = Date.now() + 12000;
  while (Date.now() < deadline) {
    await sleep(250);
    composer = findComposer();
    if (composer) return { ready: true, actions };
  }
  throw new Error('ChatGPT Images composer not found');
};
const findFileInput = () => Array.from(document.querySelectorAll("input[type='file']")).find((node) => node instanceof HTMLInputElement) || null;
const stampFileInput = (input) => {
  input.id = 'rzn-chatgpt-upload-input';
  input.setAttribute('data-rzn-upload-prepared', 'true');
  return '#rzn-chatgpt-upload-input';
};
const findAttachmentTrigger = () => {
  const composer = findComposer();
  const form = composer ? composer.closest('form') : null;
  const scopes = [form, composer?.parentElement, document].filter(Boolean);
  for (const scope of scopes) {
    const matches = Array.from(scope.querySelectorAll("button, [role='button'], label"))
      .filter(isVisible)
      .filter((node) => {
        const label = labelOf(node).toLowerCase();
        if (/send|submit|create|generate|voice|microphone|mic/.test(label)) return false;
        if (/attach|upload|photo|image|file|edit image/.test(label)) return true;
        return !label && !!node.querySelector('svg');
      });
    if (matches.length) return matches[0];
  }
  return null;
};
const ensureAttachmentInput = async () => {
  let input = findFileInput();
  if (input) return { selector: stampFileInput(input), trigger_used: false };
  const trigger = findAttachmentTrigger();
  if (!trigger) throw new Error('ChatGPT Images attachment trigger not found');
  trigger.click();
  const deadline = Date.now() + 12000;
  while (Date.now() < deadline) {
    await sleep(250);
    input = findFileInput();
    if (input) {
      return {
        selector: stampFileInput(input),
        trigger_used: true,
        trigger_label: labelOf(trigger) || null,
      };
    }
  }
  throw new Error('ChatGPT Images file input not found after opening attachment UI');
};
const surface = await ensureImagesSurface();
const attachment = await ensureAttachmentInput();
return {
  url: window.location.href,
  title: document.title,
  attachment_file_name: attachmentPath.split(/[\\/]/).pop() || attachmentPath,
  images_surface: surface,
  attachment_preparation: attachment,
};

const cleanArg = (value) => {
  const text = String(value == null ? '' : value).trim();
  return /^\{[a-zA-Z0-9_]+\}$/.test(text) ? '' : text;
};
const rawMessage = cleanArg(arg0);
const attachmentPath = cleanArg(arg1);
const parsedVariationCount = Number.parseInt(cleanArg(arg2), 10);
const variationCount = Number.isFinite(parsedVariationCount) && parsedVariationCount > 0 ? parsedVariationCount : 2;
if (!rawMessage) throw new Error('message_text is required');
if (!attachmentPath) throw new Error('attachment_file_path is required');
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
const normalize = (value) => (value || '').replace(/\u00a0/g, ' ').replace(/\s+/g, ' ').trim();
const parseTime = (value) => {
  const ts = value ? Date.parse(value) : NaN;
  return Number.isFinite(ts) ? ts : 0;
};
const isVisible = (node) => {
  if (!node || !(node instanceof Element)) return false;
  const style = window.getComputedStyle(node);
  if (style.visibility === 'hidden' || style.display === 'none') return false;
  const rect = node.getBoundingClientRect();
  return rect.width > 0 && rect.height > 0;
};
const labelOf = (node) => normalize([
  node.getAttribute('aria-label') || '',
  node.getAttribute('title') || '',
  node.getAttribute('data-testid') || '',
  node.textContent || ''
].join(' '));
const chatIdFromLocation = () => {
  const match = window.location.pathname.match(/^\/c\/([^/?#]+)/);
  return match ? match[1] : null;
};
const collectTurns = () => Array.from(document.querySelectorAll("[data-message-author-role], main article, [data-testid*='conversation-turn'], [data-testid*='conversationTurn']"));
const getConversationHistoryItems = () => {
  for (let i = 0; i < localStorage.length; i += 1) {
    const key = localStorage.key(i);
    if (!key || !/conversation-history/i.test(key)) continue;
    try {
      const raw = localStorage.getItem(key);
      if (!raw) continue;
      const parsed = JSON.parse(raw);
      const pages = parsed?.value?.pages || [];
      const items = pages.flatMap((page) => Array.isArray(page?.items) ? page.items : []);
      return items.filter((item) => item && typeof item.id === 'string');
    } catch {}
  }
  return [];
};
const snapshotConversationHistory = () => getConversationHistoryItems().map((item, index) => ({
  id: item.id,
  title: item.title || null,
  update_time: item.update_time || null,
  create_time: item.create_time || null,
  updated_at_ms: Math.max(parseTime(item.update_time), parseTime(item.create_time)),
  index,
})).filter((item) => item.id);
const makeHistoryMap = (items) => new Map(items.map((item) => [item.id, item]));
const chooseHistoryConversation = (beforeMap, afterItems) => {
  const changed = afterItems.filter((item) => {
    const previous = beforeMap.get(item.id);
    return !previous || item.updated_at_ms > previous.updated_at_ms;
  });
  const pool = changed.length ? changed : afterItems;
  if (!pool.length) return null;
  return [...pool].sort((left, right) => {
    const leftIsNew = beforeMap.has(left.id) ? 0 : 1;
    const rightIsNew = beforeMap.has(right.id) ? 0 : 1;
    if (rightIsNew !== leftIsNew) return rightIsNew - leftIsNew;
    if (right.updated_at_ms !== left.updated_at_ms) return right.updated_at_ms - left.updated_at_ms;
    return left.index - right.index;
  })[0] || null;
};
const findComposer = () => Array.from(document.querySelectorAll("#prompt-textarea, textarea[placeholder*='Describe' i], textarea[placeholder*='Message' i], textarea[placeholder*='Send a message' i], form textarea, div[role='textbox'][contenteditable='true'], [contenteditable='true'][data-testid*='composer']")).find(isVisible) || null;
const setComposerText = (node, text) => {
  node.focus();
  if (node instanceof HTMLTextAreaElement || node instanceof HTMLInputElement) {
    const setter = Object.getOwnPropertyDescriptor(Object.getPrototypeOf(node), 'value')?.set
      || Object.getOwnPropertyDescriptor(HTMLTextAreaElement.prototype, 'value')?.set
      || Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value')?.set;
    if (setter) setter.call(node, text);
    else node.value = text;
    node.dispatchEvent(new InputEvent('input', { bubbles: true, inputType: 'insertText', data: text }));
    node.dispatchEvent(new Event('change', { bubbles: true }));
    return;
  }
  node.textContent = text;
  node.dispatchEvent(new InputEvent('input', { bubbles: true, inputType: 'insertText', data: text }));
};
const findSendButton = (composer) => {
  const form = composer ? composer.closest('form') : null;
  const scopes = [form, composer?.parentElement, document].filter(Boolean);
  for (const scope of scopes) {
    const candidates = Array.from(scope.querySelectorAll("button, [role='button']"))
      .filter(isVisible)
      .filter((node) => {
        const label = labelOf(node).toLowerCase();
        const disabled = node.matches(':disabled') || node.getAttribute('aria-disabled') === 'true';
        if (disabled) return false;
        return /send prompt|send|submit|create image|create images|create|generate/.test(label);
      });
    if (candidates.length) return candidates[0];
  }
  return null;
};
const attachmentFileName = attachmentPath.split(/[\\/]/).pop() || attachmentPath;
const verifyAttachment = async () => {
  const deadline = Date.now() + 15000;
  while (Date.now() < deadline) {
    const composer = findComposer();
    const form = composer ? composer.closest('form') : null;
    const preparedInput = document.querySelector('#rzn-chatgpt-upload-input');
    const hasInputFile = !!(preparedInput && preparedInput.files && preparedInput.files.length > 0);
    const formText = normalize(form ? form.innerText : '').toLowerCase();
    const attachmentMentioned = formText.includes(attachmentFileName.toLowerCase());
    const attachmentDecorations = !!(form && form.querySelector("img, [data-testid*='upload'], [data-testid*='attachment'], button[aria-label*='remove' i], button[title*='remove' i]"));
    if (hasInputFile || attachmentMentioned || attachmentDecorations) {
      return {
        confirmed: true,
        has_input_file: hasInputFile,
        attachment_mentioned: attachmentMentioned,
        attachment_decorations: attachmentDecorations,
      };
    }
    await sleep(400);
  }
  throw new Error(`expected attachment '${attachmentFileName}' is not visible in the ChatGPT Images composer`);
};
const buildPrompt = () => {
  const normalized = normalize(rawMessage);
  if (!normalized) return normalized;
  if (/\b(?:exactly|create)\s+\d+\s+(?:distinct\s+)?(?:image\s+)?variations?\b/i.test(normalized)) {
    return normalized;
  }
  return `${normalized}\n\nGenerate exactly ${variationCount} distinct image variations. Return the final images in this chat.`;
};
const historyBeforeItems = snapshotConversationHistory();
const historyBeforeMap = makeHistoryMap(historyBeforeItems);
const turnsBefore = collectTurns().length;
const attachmentState = await verifyAttachment();
const finalPrompt = buildPrompt();
let composer = findComposer();
if (!composer) throw new Error('ChatGPT Images composer not found');
setComposerText(composer, finalPrompt);
await sleep(250);
composer = findComposer() || composer;
const sendButton = findSendButton(composer);
if (!sendButton) throw new Error('ChatGPT Images send button not found');
sendButton.click();
let chatId = chatIdFromLocation();
let historyConversation = null;
let historySignal = 'none';
let turnCount = collectTurns().length;
const deadline = Date.now() + 45000;
while (Date.now() < deadline) {
  chatId = chatIdFromLocation();
  const historyAfterItems = snapshotConversationHistory();
  const candidate = chooseHistoryConversation(historyBeforeMap, historyAfterItems);
  const previous = candidate ? historyBeforeMap.get(candidate.id) : null;
  const candidateIsFresh = !!candidate && (!previous || candidate.updated_at_ms > previous.updated_at_ms);
  if (candidate) {
    historyConversation = candidate;
    historySignal = candidateIsFresh ? (previous ? 'updated_history_item' : 'new_history_item') : 'stale_history_fallback';
  }
  turnCount = collectTurns().length;
  if (chatId || candidateIsFresh || turnCount > turnsBefore) break;
  await sleep(turnCount > turnsBefore ? 1200 : 750);
}
return {
  url: window.location.href,
  title: document.title,
  chat_id: chatIdFromLocation() || (historySignal !== 'stale_history_fallback' && historyConversation ? historyConversation.id : null),
  attachment_state: attachmentState,
  message_sent: rawMessage,
  submitted_prompt: finalPrompt,
  variation_count: variationCount,
  turn_count: turnCount,
  history_signal: historySignal,
  history_before_count: historyBeforeItems.length,
  history_conversation: historyConversation ? {
    id: historyConversation.id,
    title: historyConversation.title || null,
    update_time: historyConversation.update_time || null,
    create_time: historyConversation.create_time || null,
  } : null,
};
